import{_ as a,o as r,c as d,a2 as e}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"出金失败怎么办","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"troubleshooting/withdrawal-failure.md","filePath":"zh-CN/troubleshooting/withdrawal-failure.md"}'),o={name:"troubleshooting/withdrawal-failure.md"};function l(i,t,h,n,s,p){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="出金失败怎么办" tabindex="-1">出金失败怎么办 <a class="header-anchor" href="#出金失败怎么办" aria-label="Permalink to &quot;出金失败怎么办&quot;">​</a></h1><p>出金申请被驳回或长时间未到账，按以下步骤逐项排查。</p><h2 id="第一步-查看驳回原因" tabindex="-1">第一步：查看驳回原因 <a class="header-anchor" href="#第一步-查看驳回原因" aria-label="Permalink to &quot;第一步：查看驳回原因&quot;">​</a></h2><p>进入长桥 App → 资产 → 提取资金 → 出金记录，找到该笔申请：</p><ul><li><strong>状态「已驳回」</strong>：点击记录查看驳回原因，参照下方表格处理</li><li><strong>状态「处理中」</strong>：仍在正常处理流程内，参照「到账时间」等待</li><li><strong>状态「已完成」但银行未到账</strong>：跳至第三步</li></ul><h3 id="常见驳回原因及处理方式" tabindex="-1">常见驳回原因及处理方式 <a class="header-anchor" href="#常见驳回原因及处理方式" aria-label="Permalink to &quot;常见驳回原因及处理方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>驳回原因</th><th>处理方式</th></tr></thead><tbody><tr><td>银行账户名与证券账户名不一致</td><td>只能出金至同名银行账户，更换本人同名账户重新申请</td></tr><tr><td>银行卡未绑定或已失效</td><td>在 App → 银行卡管理重新绑定，再提交出金</td></tr><tr><td>可提金额不足</td><td>检查资金是否已结算（见第二步）；或账户存在欠款影响可提金额</td></tr><tr><td>超出单笔或日限额</td><td>分多次提交，或申请大额出金审核</td></tr><tr><td>账户存在限制</td><td>联系客服确认账户状态</td></tr><tr><td>出金至第三方账户</td><td>不支持出金至非本人账户、联名账户或支付平台</td></tr></tbody></table><h2 id="第二步-确认资金已结算" tabindex="-1">第二步：确认资金已结算 <a class="header-anchor" href="#第二步-确认资金已结算" aria-label="Permalink to &quot;第二步：确认资金已结算&quot;">​</a></h2><p>交易所得资金需等待结算后才可出金：</p><table tabindex="0"><thead><tr><th>市场</th><th>结算周期</th></tr></thead><tbody><tr><td>港股</td><td>T+2（交易日起算第 2 个工作日）</td></tr><tr><td>美股</td><td>T+1（交易日起算第 1 个工作日）</td></tr><tr><td>新加坡股票</td><td>T+2</td></tr></tbody></table><p>如果当日刚完成交易，资金尚在结算中，需等结算完成后才可出金。<br> App → 资产 → 现金页面可查看「可出金余额」（已结算）与「总资产」的差异。</p><h2 id="第三步-确认到账时间" tabindex="-1">第三步：确认到账时间 <a class="header-anchor" href="#第三步-确认到账时间" aria-label="Permalink to &quot;第三步：确认到账时间&quot;">​</a></h2><p>已审批通过的出金申请，按以下时间预期到账：</p><p><strong>香港账户 — FPS 转数快（港元）</strong></p><table tabindex="0"><thead><tr><th>提交时间</th><th>预计到账</th></tr></thead><tbody><tr><td>交易日 09:00–15:30</td><td>最快 2 小时内</td></tr><tr><td>其他时段</td><td>下一交易日 10:00 前</td></tr></tbody></table><p><strong>香港账户 — 网银转账（港元 / 美元）</strong></p><p>交易日 15:30 前提交 → 当天出金；15:30 后 → 次一交易日出金</p><p><strong>电汇（美元）</strong>：2–5 个银行工作日</p><p><strong>新加坡账户</strong>：PayNow 实时到账；DDA 实时到账</p><p>如已超出上述时间仍未收到，继续下一步。</p><h2 id="第四步-确认收款银行账号" tabindex="-1">第四步：确认收款银行账号 <a class="header-anchor" href="#第四步-确认收款银行账号" aria-label="Permalink to &quot;第四步：确认收款银行账号&quot;">​</a></h2><p>若收款账号填写有误，资金可能转入错误账户。联系银行查询该笔汇款的实际收款方。</p><p>如确认银行账号有误：</p><ol><li>立即联系长桥客服说明情况</li><li>提供汇款流水号和转账金额</li><li>长桥将协助联系银行追回或重新处理</li></ol><h2 id="仍未解决" tabindex="-1">仍未解决 <a class="header-anchor" href="#仍未解决" aria-label="Permalink to &quot;仍未解决&quot;">​</a></h2><p>准备以下信息联系客服：</p><ul><li>出金申请的记录截图（含申请时间、金额、状态）</li><li>银行流水截图（如已从银行账户扣款）</li><li>收款银行账号信息</li></ul><p><strong>在线客服</strong>：长桥 App → 我的 → 帮助与客服 → 在线客服<br><strong>客服热线</strong>：4000712688</p>',28)])])}const c=a(o,[["render",l]]);export{u as __pageData,c as default};
